import React, { useState } from "react";
import { FaFacebook, FaTwitter, FaLinkedin } from "react-icons/fa";
import emailjs from "emailjs-com";
import emailjskey from "../emailjskey";

const ContactSocial = () => {
  const [name, setName] = useState("");
  const [message, setMessage] = useState("");
  const [isSendingEmail, setIsSendingEmail] = useState(false);
  const [sentMessage, setMessageSent] = useState(false);
  const [errorSendingMessage, setErrorSendingMessage] = useState(false);
  const handleNameChange = (e) => {
    setName(e.target.value);
  };

  const handleMessageChange = (e) => {
    setMessage(e.target.value);
  };

  const sendMessage = (e) => {
    e.preventDefault();
    if (name.trim() === "" || message.trim() === "") return;
    setIsSendingEmail(true);
    emailjs
      .send(
        emailjskey.SERVICE_ID,
        emailjskey.TEMPLATE_ID,
        { name, message },
        emailjskey.USER_ID
      )
      .then((result) => {
        setMessageSent(true);
        setIsSendingEmail(false);
        setTimeout(() => {
          setMessageSent(false);
        }, 5000);
      })
      .catch((err) => {
        setErrorSendingMessage(true);
        setTimeout(() => {
          setIsSendingEmail(false);
          setErrorSendingMessage(false);
        }, 5000);
      });
  };
  return (
    <footer className="contact-social" id="contact-me">
      <div className="center">
        <aside className="left">
          <h3 className="title">Send a direct message to me.</h3>
          <div className="form-container">
            <form onSubmit={sendMessage}>
              <div className="input-container">
                <input
                  type="text"
                  placeholder="Your name"
                  onChange={handleNameChange}
                  value={name}
                />
              </div>
              <div className="input-container">
                <textarea
                  placeholder="Your message"
                  onChange={handleMessageChange}
                  value={message}
                />
              </div>
              <div className="">
                <button
                  className="submit-btn"
                  disabled={isSendingEmail || sentMessage}
                >
                  {isSendingEmail
                    ? "Sending email mate..."
                    : sentMessage
                    ? "Message sent mate.."
                    : errorSendingMessage
                    ? "oops, try again"
                    : "Send message"}
                </button>
              </div>
            </form>
          </div>
        </aside>
        <aside className="right">
          <ul className="social-navigation">
            <li>
              <a href="#facebook">
                <FaFacebook /> Facebook
              </a>
            </li>
            <li>
              <a href="#facebook">
                <FaTwitter /> Twitter
              </a>
            </li>
            <li>
              <a href="#facebook">
                <FaLinkedin /> LinkedIn
              </a>
            </li>
            {/* <li>
          <a href="#contact">
            <FaEnvelope />
          </a>
        </li> */}
          </ul>
          <div className="download-resume">
            <h3>Download my Resume.</h3>
            <a href="" className="download-resume">
              Download my Resume
            </a>
          </div>
        </aside>
      </div>
    </footer>
  );
};

export default ContactSocial;
